  MAGICBELL_API_KEY: apiKey,
  MAGICBELL_SECRET_KEY: secretKey,
  MAGICBELL_PROJECT_TOKEN: projectToken,
  ZEALT_RUN_ID: runId,
} = process.env;

const requiredEnv = {
  MAGICBELL_API_KEY: apiKey,
  MAGICBELL_SECRET_KEY: secretKey,
  MAGICBELL_PROJECT_TOKEN: projectToken,
  ZEALT_RUN_ID: runId,
